import { IconCheck, IconLink } from '@tabler/icons-react'
import { useEffect, useState, type HTMLAttributes, type ReactNode } from 'react'
import { getI18n } from '@/i18n/i18n-context'

/**
 * Split origignal document title and the anchor generated by gen-doc cli.
 *
 * @param mixedTitle original title, title and anchor are mixed in it.
 * @returns title and anchor strings.
 */
function splitTitleAndAnchor(mixedTitle: ReactNode): {
  title: ReactNode
  anchor: string
} {
  // eslint-disable-next-line @typescript-eslint/no-unsafe-assignment
  const titleArray = Array.isArray(mixedTitle) ? [...mixedTitle] : [mixedTitle]
  const anchor = titleArray.at(-1) as string
  const title = titleArray.slice(0, -1) as ReactNode

  return {
    title,
    anchor: `title-${anchor}`,
  }
}

function _LinkIcon({
  anchor,
  className,
  showCopiedIcon,
}: {
  anchor: string
  className?: string
  showCopiedIcon: boolean
}) {
  const tr = getI18n().acticlePage.components.heading.copyButton
  return (
    <a href={`#${anchor}`} className={className}>
      {showCopiedIcon ? (
        <IconCheck size={20} title={tr.copiedTooltip} />
      ) : (
        <IconLink size={20} title={tr.tooltip} className="hover:text-primary" />
      )}
    </a>
  )
}

interface _HeadingProps extends HTMLAttributes<HTMLHeadingElement> {
  level: 1 | 2 | 3 | 4 | 5 | 6
  children: ReactNode
  className?: string
  [key: string]: unknown
}

const HEADING_TAGS = {
  1: 'h1',
  2: 'h2',
  3: 'h3',
  4: 'h4',
  5: 'h5',
  6: 'h6',
} as const

export default function Heading({
  level,
  className,
  children,
  ...props
}: _HeadingProps) {
  const [showIcon, setShowIcon] = useState(false)
  const [justClicked, setJustClicked] = useState(false)

  const { title, anchor } = splitTitleAndAnchor(children)

  const commonClass = 'flex gap-2 my-article-paragraph items-center'
  const finalClassName = [commonClass, className].filter(Boolean).join(' ')
  const Tag = HEADING_TAGS[level]

  // After link button clicked, show check button for some duration and then
  // hide it.
  useEffect(() => {
    if (!justClicked) {
      return
    }

    const timer = setTimeout(() => {
      setShowIcon(false)
      setJustClicked(false)
    }, 2000)

    return () => {
      clearTimeout(timer)
    }
  }, [justClicked])

  return (
    <>
      <Tag
        id={anchor}
        className={finalClassName}
        onMouseEnter={() => {
          setShowIcon(true)
        }}
        onMouseLeave={() => {
          if (justClicked) {
            // The onClick handler delegates icon visibility.
            return
          }
          setShowIcon(false)
        }}
        onClick={() => {
          setJustClicked(true)
        }}
        {...props}
      >
        {title}
        <_LinkIcon
          showCopiedIcon={justClicked}
          anchor={anchor}
          className={
            (showIcon ? '' : 'hidden') + (justClicked ? 'text-primary' : '')
          }
        />
      </Tag>
    </>
  )
}
